#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
int tree[MAX_N];
int visited[MAX_N];
int dfs(int node, int target) {
    if (visited[node]) return 0;
    visited[node] = 1;
    if (node == target) return 1;
    for (int i = 0; i < tree[node]; i++) {
        int child = tree[node * (i + 1)];
        if (dfs(child, target)) return 1;
    }
    return 0;
}
int main() {
    int T, n, q;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &q);
        for (int i = 0; i < n - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            tree[u] = v;
        }
        for (int i = 0; i < q; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            int count = 0;
            for (int j = 1; j <= n; j++) {
                if (dfs(j, u) && dfs(j, v)) count++;
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

