tree = [[] for _ in range(MAX_N)]
visited = [False] * MAX_N
def dfs(node, target):
    if visited[node]: return 0
    visited[node] = True
    if node == target: return 1
    for child in tree[node]:
        if dfs(child, target): return 1
    return 0

