    const T = +lines[l++];
    for (let i = 0; i < T; i++) {
        const [n, q] = lines[l++].trim().split(' ').map(Number);
        const tree = Array.from({ length: n + 1 }, () => []);
        for (let j = 0; j < n - 1; j++) {
            const [u, v] = lines[l++].trim().split(' ').map(Number);
            tree[u].push(v);
        }
        for (let j = 0; j < q; j++) {
            const [u, v] = lines[l++].trim().split(' ').map(Number);
            let count = 0;
            const visited = Array.from({ length: n + 1 }, () => false);
            for (let k = 1; k <= n; k++) {
                if (dfs(k, u, tree, visited) && dfs(k, v, tree, visited)) count++;
            }
            console.log(count);
